//! The HTTP server + request dispatch.
//!
//! This mirrors the framework's `crates/cli/src/cmd_serve.rs` wiring: build a
//! template engine from `frontend/*.html`, load the `backend/page.json` context,
//! route through `backend/routes.json`, and render `content/**.md` into page
//! templates. The golf-specific content routes (news, handbook, legal) are
//! handled explicitly, the way the framework handles `/changelog` and `/docs/*`.
//!
//! Static assets are served directly and `/utilities.css` is generated by the
//! atomic CSS engine. The Phase-3 booking engine adds a server-rendered booking
//! calendar at `/` plus the JSON booking API (`/api/availability`,
//! `/api/slot-price`, `/api/book`, `/api/bookings`) backed by [`booking::Store`].
//! The remaining dynamic pages (shop, account, admin) still render "coming soon"
//! placeholders — see PORT.md.

use crate::auth;
use crate::booking::{self, Store as BookingStore};
use crate::cart::{self, Store as CartStore};
use crate::checkout::{self, Store as CheckoutStore};
use crate::collections_api::CollectionsApi;
use crate::content;
use crate::giftcards::{self, IssueParams, Store as GiftCardStore};
use crate::mime;
use crate::shop;
use akurai_http::form::{field, parse_urlencoded};
use akurai_http::{
    Method, MiddlewareStack, Reply, Request, RequestLogger, Response, SecurityHeaders, Server,
    Timing,
};
use akurai_json::Value;
use akurai_router::Router;
use akurai_template::Engine;
use std::fs;
use std::io;
use std::path::{Path, PathBuf};
use std::sync::Arc;
use std::time::{SystemTime, UNIX_EPOCH};

const VERSION: &str = env!("CARGO_PKG_VERSION");

/// HTML and plain static assets revalidate on every request — they change on
/// deploy and must never be cached stale by a browser.
const NO_CACHE: &str = "no-cache";

pub struct Config {
    pub host: String,
    pub port: u16,
    /// The `frontend/` directory holding templates + static assets.
    pub dir: PathBuf,
}

/// Boot the server and serve until killed.
pub fn run(cfg: Config) -> io::Result<()> {
    if !cfg.dir.is_dir() {
        return Err(io::Error::new(
            io::ErrorKind::NotFound,
            format!("frontend directory not found: {}", cfg.dir.display()),
        ));
    }

    let addr = format!("{}:{}", cfg.host, cfg.port);
    let server = Server::bind(&addr)?;
    let local = server.local_addr()?;
    let root = cfg.dir.clone();

    // The booking database lives alongside the app dir (sibling of `frontend/`),
    // in `data/booking/`. Gitignored — never committed (see .gitignore).
    let data_dir = data_dir(&root);
    let store = Arc::new(BookingStore::open(&data_dir)?);
    let cart_store = Arc::new(CartStore::open(&cart_data_dir(&root))?);
    let settings_store = Arc::new(crate::admin::settings::Store::open(&admin_data_dir(&root))?);
    let giftcard_store = Arc::new(GiftCardStore::open(&giftcard_data_dir(&root))?);
    let checkout_store = Arc::new(CheckoutStore::open(&checkout_data_dir(&root))?);

    // Auth stores live under data/auth/ (sibling of data/booking/).
    let auth_data = data_dir
        .parent()
        .map(|p| p.join("auth"))
        .unwrap_or_else(|| data_dir.join("auth"));
    let auth = Arc::new(auth::State::open(&auth_data)?);

    // Auto-generated REST API from backend/collections.toml. Mounts a live CRUD
    // + ?search surface under /api/collections/<name>/records. An absent file →
    // zero collections and the server behaves exactly as before; a malformed
    // schema fails `serve` loudly here rather than silently dropping routes. The
    // store opens data/{collections,embeddings,blobs}.db under the project root
    // (the sibling-of-`frontend/` dir that already holds backend/ and data/).
    let project_root = root
        .parent()
        .map(Path::to_path_buf)
        .unwrap_or_else(|| root.clone());
    let collections_api = Arc::new(CollectionsApi::open(&project_root).map_err(|msg| {
        io::Error::new(
            io::ErrorKind::InvalidData,
            format!("collections.toml: {msg}"),
        )
    })?);

    println!("Golfsetrið Akureyri — golfsetridak v{VERSION} (on AkurAI-Framework)");
    println!("  serving {}", root.display());
    println!("  booking db: {}", data_dir.display());
    println!("  cart db: {}", cart_data_dir(&root).display());
    println!("  admin db: {}", admin_data_dir(&root).display());
    println!("  checkout db: {}", checkout_data_dir(&root).display());
    println!("  → http://{local}");
    println!("  giftcards db: {}", giftcard_data_dir(&root).display());
    println!("  utilities.css: served at /utilities.css");
    println!(
        "  collections: {} mounted from backend/collections.toml",
        collections_api.collections().len()
    );

    // Outermost first: security headers stamp every reply, then logging + timing.
    let middleware = MiddlewareStack::new()
        .push(SecurityHeaders)
        .push(RequestLogger)
        .push(Timing);

    server.run_with(middleware, move |req: &Request| {
        dispatch_reply(
            &root,
            &store,
            &cart_store,
            &settings_store,
            &giftcard_store,
            &checkout_store,
            &collections_api,
            &auth,
            req,
        )
    })
}

/// Current wall-clock time as epoch-milliseconds (UTC).
fn now_ms() -> i64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_millis() as i64)
        .unwrap_or(0)
}

/// Resolve the booking database directory for a given `frontend/` dir: a
/// `data/booking/` sibling of the app dir. Shared by `serve` and `seed-demo`.
pub fn data_dir(frontend_dir: &Path) -> PathBuf {
    frontend_dir
        .parent()
        .map(|p| p.join("data/booking"))
        .unwrap_or_else(|| frontend_dir.join("data/booking"))
}

fn cart_data_dir(frontend_dir: &Path) -> PathBuf {
    frontend_dir
        .parent()
        .map(|p| p.join("data/cart"))
        .unwrap_or_else(|| frontend_dir.join("data/cart"))
}

fn admin_data_dir(frontend_dir: &Path) -> PathBuf {
    frontend_dir
        .parent()
        .map(|p| p.join("data/admin"))
        .unwrap_or_else(|| frontend_dir.join("data/admin"))
}

fn giftcard_data_dir(frontend_dir: &Path) -> PathBuf {
    frontend_dir
        .parent()
        .map(|p| p.join("data/giftcards"))
        .unwrap_or_else(|| frontend_dir.join("data/giftcards"))
}

fn checkout_data_dir(frontend_dir: &Path) -> PathBuf {
    frontend_dir
        .parent()
        .map(|p| p.join("data/checkout"))
        .unwrap_or_else(|| frontend_dir.join("data/checkout"))
}

/// Seed a demo user, a klippikort package grant (`slots` slots) and an active
/// subscription, so package/subscription bookings can be exercised before the
/// purchase/admin flows (other agents' scope) land. Mirrors the source's
/// `seed.ts` / `seed-demo.ts`. Idempotent: re-running overwrites the same ids.
pub fn seed_demo(frontend_dir: &Path, slots: i64) -> io::Result<()> {
    let store = BookingStore::open(&data_dir(frontend_dir))?;
    let now = now_ms();
    let today = booking::time::day_start(now);

    // A standard demo customer and a fixed-price (VIP) customer.
    store.put_user("demo", None)?;
    store.put_user("vip", Some(1000))?;

    // A klippikort grant with `slots` remaining slots.
    store.put_user_package(&booking::UserPackage {
        id: "demo-pkg".into(),
        user_id: "demo".into(),
        remaining: slots,
        package_name: Some("Demo Package".into()),
        slot_count: Some(slots),
    })?;

    // An active subscription window (yesterday → +60 days), limit 2/day.
    store.put_user_subscription(&booking::UserSubscription {
        id: "demo-sub".into(),
        user_id: "demo".into(),
        valid_from: booking::time::add_days(today, -1),
        valid_until: booking::time::add_days(today, 60),
        daily_limit: 2,
    })?;

    let remaining = store
        .user_package("demo-pkg")
        .map(|p| p.remaining)
        .unwrap_or(0);
    println!("Seeded demo data into {}", data_dir(frontend_dir).display());
    println!("  user        demo  (no fixed price)");
    println!("  user        vip   (fixed price 1000)");
    println!("  package     demo-pkg  remaining={remaining}");
    println!("  subscription demo-sub  daily_limit=2 (active 61 days)");
    Ok(())
}

/// Top-level reply dispatcher — handles auth routes before content routes.
#[allow(clippy::too_many_arguments)]
fn dispatch_reply(
    root: &Path,
    store: &BookingStore,
    cart_store: &CartStore,
    settings_store: &crate::admin::settings::Store,
    giftcard_store: &GiftCardStore,
    checkout_store: &CheckoutStore,
    collections_api: &CollectionsApi,
    auth: &auth::State,
    req: &Request,
) -> Reply {
    // Tick the gift-card delivery scheduler on every request. For the low-traffic
    // golf-club context this is adequate — no separate timer thread required.
    let _ = giftcard_store.run_delivery_scheduler(now_ms());

    let path = req.path.as_str();
    match path {
        "/login" => auth::login(auth, root, req, store),
        "/logout" => auth::logout(auth, req),
        "/api/auth/dev-login" => auth::dev_login(auth, req, store),
        _ => Reply::Response(dispatch(
            root,
            store,
            cart_store,
            settings_store,
            giftcard_store,
            checkout_store,
            collections_api,
            auth,
            req,
        )),
    }
}

/// Route one request to a buffered response. `root` is the `frontend/` dir.
#[allow(clippy::too_many_arguments)]
fn dispatch(
    root: &Path,
    store: &BookingStore,
    cart_store: &CartStore,
    settings_store: &crate::admin::settings::Store,
    giftcard_store: &GiftCardStore,
    checkout_store: &CheckoutStore,
    collections_api: &CollectionsApi,
    auth: &auth::State,
    req: &Request,
) -> Response {
    let path = req.path.as_str();
    match path {
        "/utilities.css" => utilities(root),
        "/api/health" => json(200, &health()),
        "/api/version" => api_version(req),
        "/api/me" => api_me(auth, req),
        "/api/user-packages" => api_user_packages(store, auth, req),

        // Booking API (Phase 3). Methods are checked inside each handler.
        "/api/availability" => api_availability(store, req, auth),
        "/api/slot-price" => api_slot_price(collections_api, req, auth),
        "/api/book" => api_book(store, collections_api, req, auth),
        "/api/bookings" => api_bookings(store, req, auth),
        "/api/book-batch" => api_book_batch(store, collections_api, req, auth),
        "/api/users" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_users(collections_api, store, req, None)
        }
        p if p.starts_with("/api/users/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_users(collections_api, store, req, Some(slug_of(p, "/api/users/")))
        }
        p if p.starts_with("/api/admin/pricing/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_pricing(collections_api, req, slug_of(p, "/api/admin/pricing/"))
        }
        "/api/admin/upload" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_upload(root, req)
        }
        "/api/shop/products" => api_shop_products(collections_api, req),
        "/api/shop/categories" => api_shop_categories(collections_api, req),
        "/api/admin/shop/products" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_products(collections_api, req, None)
        }
        "/api/admin/shop/categories" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_categories(collections_api, req, None)
        }
        "/api/cart" => api_cart(cart_store, req, auth),
        "/api/cart/items" => api_cart_items(store, collections_api, cart_store, req, None, auth),
        "/api/cart/items/bulk" => {
            api_cart_items_bulk(store, collections_api, cart_store, req, auth)
        }

        // Gift card API (Phase 3). Public lookup + redeem; admin issuance/listing gated.
        "/api/cart/gift-card/lookup" => api_giftcard_lookup(giftcard_store, cart_store, req),
        "/api/cart/gift-card/redeem" => api_giftcard_redeem(giftcard_store, cart_store, req),
        "/api/admin/gift-cards" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_giftcards(giftcard_store, req, None)
        }
        p if p.starts_with("/api/admin/gift-cards/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_giftcards(
                giftcard_store,
                req,
                Some(slug_of(p, "/api/admin/gift-cards/")),
            )
        }

        // Checkout + payment APIs.
        "/api/cart/checkout" => checkout::api_checkout(cart_store, checkout_store, auth, req),
        "/api/payments/landsbankinn/callback" => {
            checkout::api_landsbankinn_callback(cart_store, checkout_store, store, req)
        }
        p if p.starts_with("/api/admin/shop/products/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_products(
                collections_api,
                req,
                Some(slug_of(p, "/api/admin/shop/products/")),
            )
        }
        p if p.starts_with("/api/admin/shop/categories/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return json(401, &error_value("Unauthorized"));
            }
            api_admin_categories(
                collections_api,
                req,
                Some(slug_of(p, "/api/admin/shop/categories/")),
            )
        }
        p if p.starts_with("/api/cart/items/") => api_cart_items(
            store,
            collections_api,
            cart_store,
            req,
            Some(slug_of(p, "/api/cart/items/")),
            auth,
        ),

        // Subscription member sharing (Phase 3.5). Auth-gated; the owner of the
        // subscription manages members. Routes:
        //   GET/POST  /api/user-subscriptions/:id/members
        //   DELETE    /api/user-subscriptions/:id/members/:memberId
        p if p.starts_with("/api/user-subscriptions/") && p.contains("/members") => {
            api_subscription_members(store, p, req, auth)
        }

        // Home: the server-rendered booking calendar (replaces the placeholder).
        "/" => calendar_page(root, store, collections_api, auth, req),

        // Checkout + payment result pages (Phase 3 checkout flow).
        "/checkout" => checkout::page_checkout(root, cart_store, auth, req),
        "/checkout/bank-transfer" => checkout::page_bank_transfer(root, checkout_store, auth, req),
        "/checkout/landsbankinn" => checkout::page_landsbankinn(root, auth, req),
        "/checkout/success" => checkout::page_success(root, auth, req),
        "/checkout/cancel" => checkout::page_cancel(root, auth, req),

        // Markdown content pages — handled explicitly (mirrors the framework's
        // explicit `/changelog` and `/docs/*` routes).
        "/frettir" => news_list(root, auth, req),
        p if p.starts_with("/frettir/") => news_detail(root, slug_of(p, "/frettir/"), auth, req),
        "/notendahandbok" => handbook_list(root, auth, req),
        p if p.starts_with("/notendahandbok/") => {
            handbook_detail(root, slug_of(p, "/notendahandbok/"), auth, req)
        }
        "/personuvernd" => legal(root, "personuvernd", auth, req),
        "/skilmalar" => legal(root, "skilmalar", auth, req),
        "/um-okkur" => about(root, auth, req),
        "/verslun" => shop_page(root, collections_api, cart_store, auth, req),
        "/my" => my_page(root, store, auth, req),
        "/my/verslun" => shop_page(root, collections_api, cart_store, auth, req),
        "/my/verslun/karfa" => cart_page(root, cart_store, req, auth),
        "/admin/vorur" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_products_page(root, collections_api, auth, req)
        }
        "/admin/vorur/flokkar" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_categories_page(root, collections_api, auth, req)
        }
        "/admin/vorur/nytt" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_product_form_page(root, collections_api, None, auth, req)
        }
        p if p.starts_with("/admin/vorur/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_product_form_page(
                root,
                collections_api,
                Some(slug_of(p, "/admin/vorur/")),
                auth,
                req,
            )
        }

        // Admin API endpoints — stats and dashboard
        "/api/admin/dashboard" => crate::admin::api_admin_dashboard(store, req, auth),
        "/api/admin/stats" => crate::admin::api_admin_stats(store, req, auth),

        // Admin HTML pages
        "/admin" => crate::admin::admin_home_redirect(),
        "/admin/bookings" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            crate::admin::admin_bookings_page(root, store, auth, req)
        }
        "/admin/payments" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            crate::admin::admin_payments_page(root, checkout_store, auth, req)
        }
        "/admin/users" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            crate::admin::admin_users_page(root, collections_api, auth, req)
        }
        "/admin/settings" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            crate::admin::admin_settings_page(root, settings_store, auth, req)
        }
        "/admin/sms" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            crate::admin::admin_sms_page(root, settings_store, auth, req)
        }
        "/admin/tilkynningar" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            crate::admin::admin_announcements_page(root, store, auth, req)
        }

        // Gift card pages. Public purchase page + admin issuance/tracking.
        "/gjafabref" => giftcard_page(root, auth, req),
        "/admin/gift-cards" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_giftcards_page(root, giftcard_store, auth, req)
        }
        "/admin/gift-cards/new" => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_giftcard_new_page(root, auth, req)
        }
        p if p.starts_with("/admin/gift-cards/") => {
            if !auth.require_role(req, auth::Role::Admin) {
                return Response::new(302).with_header("Location", "/login");
            }
            admin_giftcard_detail_page(
                root,
                giftcard_store,
                slug_of(p, "/admin/gift-cards/"),
                auth,
                req,
            )
        }

        // Auto-API: backend/collections.toml mounted as live CRUD + ?search.
        // Handled before the generic /api/* 404 below. A non-collections shape
        // makes `dispatch` return None and we answer 404 (it is an /api/ path,
        // which would 404 anyway). The 4-segment records/id/field GET streams a
        // stored File-field blob as raw bytes via `download`.
        p if p == "/api/collections" || p.starts_with("/api/collections/") => {
            let rest = p.trim_start_matches("/api/collections");
            let segments: Vec<&str> = rest.split('/').filter(|s| !s.is_empty()).collect();
            if let [name, "records", id, field] = segments.as_slice() {
                if req.method == Method::Get {
                    return collections_api.download(name, id, field);
                }
            }
            let content_type = req.header("Content-Type");
            match collections_api.dispatch(
                &req.method,
                &segments,
                req.query.as_deref(),
                content_type,
                &req.body,
            ) {
                Some((status, value)) => json(status, &value),
                None => json(404, &error_value("not found")),
            }
        }

        // Unknown API routes are a hard JSON 404, never an HTML fallback.
        p if p.starts_with("/api/") => json(404, &error_value("not found")),

        // Deep-link booking page for a specific slot (mirrors `book/[slot]`).
        p if p.starts_with("/book/") => {
            book_slot_page(root, collections_api, slug_of(p, "/book/"), auth, req)
        }

        // Admin-uploaded product images (served before the static-asset arm so
        // the `.png`/`.jpg` extension doesn't route into `frontend/`).
        p if p.starts_with("/uploads/") => serve_upload(root, p),

        // Static assets (anything whose last segment has a non-`.html` extension).
        p if is_static_asset(p) => serve_static(root, p),

        // Everything else is a declarative page from routes.json (the remaining
        // placeholders for the dynamic pages that arrive in later phases).
        p => render_page_routed(root, p, auth, req),
    }
}

// ---- booking API ----------------------------------------------------------

/// Parse the request query string into `(key, value)` pairs.
fn query_pairs(req: &Request) -> Vec<(String, String)> {
    req.query
        .as_deref()
        .map(parse_urlencoded)
        .unwrap_or_default()
}

/// Resolve the acting user id from the session cookie.
///
/// The session email is the stable user id used by the booking store. Returns
/// `None` when unauthenticated, causing the booking APIs to respond with 401.
fn resolve_user_id(req: &Request, _body: Option<&Value>, auth: &auth::State) -> Option<String> {
    auth.current_user(req).map(|u| u.email)
}

/// `GET /api/availability?date=YYYY-MM-DD&days=N&userId=X` — slots + prices.
fn api_availability(store: &BookingStore, req: &Request, auth: &auth::State) -> Response {
    if req.method != Method::Get {
        return json(405, &error_value("method not allowed"));
    }
    let q = query_pairs(req);
    let now = now_ms();
    let start = match field(&q, "date") {
        Some(d) => match booking::time::parse_date(d) {
            Some(ms) => ms,
            None => return json(400, &error_value("Invalid date")),
        },
        None => booking::time::day_start(now),
    };
    // Clamp days to 1..=30, matching the source route.
    let days = field(&q, "days")
        .and_then(|s| s.parse::<i64>().ok())
        .unwrap_or(7)
        .clamp(1, 30);
    let user = resolve_user_id(req, None, auth);
    let availability = store.availability(start, days, user.as_deref(), now);
    json(200, &availability_value(&availability))
}

/// `GET /api/slot-price?hour=H&userId=X` — the effective price for an hour.
fn api_slot_price(api: &CollectionsApi, req: &Request, auth: &auth::State) -> Response {
    if req.method != Method::Get {
        return json(405, &error_value("method not allowed"));
    }
    let q = query_pairs(req);
    let hour = field(&q, "hour").and_then(|s| s.parse::<i64>().ok());
    let Some(hour) = hour.filter(|h| (0..=23).contains(h)) else {
        return json(400, &error_value("hour must be 0-23"));
    };
    let user = resolve_user_id(req, None, auth);
    let rules = collection_pricing_rules(api);
    let fixed = user
        .as_deref()
        .and_then(|u| collection_user_fixed_price(api, u));
    let price = booking::pricing::effective_slot_price(hour, &rules, fixed);
    json(
        200,
        &Value::Object(vec![("price".into(), Value::Int(price))]),
    )
}

/// `POST /api/book` — create a booking. Body: `{ userId, slotTime, paymentType,
/// userPackageId?, userSubscriptionId?, notes? }`.
fn api_book(
    store: &BookingStore,
    api: &CollectionsApi,
    req: &Request,
    auth: &auth::State,
) -> Response {
    if req.method != Method::Post {
        return json(405, &error_value("method not allowed"));
    }
    let body = match akurai_json::parse(&req.body_str()) {
        Ok(v) => v,
        Err(_) => return json(400, &error_value("invalid JSON body")),
    };

    let Some(user_id) = resolve_user_id(req, Some(&body), auth) else {
        return json(401, &error_value("Unauthorized"));
    };

    let payment_type = body.get("paymentType").and_then(Value::as_str);
    let slot_raw = body.get("slotTime");
    let (Some(payment_type), Some(slot_raw)) = (payment_type, slot_raw) else {
        return json(400, &error_value("slotTime and paymentType are required"));
    };
    // slotTime may arrive as an ISO string or an integer epoch-ms.
    let slot_ms = match slot_raw {
        Value::Int(ms) => Some(*ms),
        Value::Str(s) => booking::time::parse_instant(s),
        _ => None,
    };
    let Some(slot_ms) = slot_ms else {
        return json(400, &error_value("Invalid slotTime"));
    };

    let now = now_ms();
    let has_package = payment_type == "package";
    if let Err(e) = booking::validation::validate_booking_request(slot_ms, has_package, now) {
        return json(400, &error_value(&e));
    }

    let ref_id = if payment_type == "subscription" {
        body.get("userSubscriptionId").and_then(Value::as_str)
    } else {
        body.get("userPackageId").and_then(Value::as_str)
    };
    let notes = body.get("notes").and_then(Value::as_str);

    // Single-payment price comes from the collections pricing rules (the same
    // source `/api/slot-price` reads) plus the user's collections `fixed_price`,
    // so the charged price always matches an admin pricing change. Package /
    // subscription bookings are covered (price 0 / accounted), so no resolved
    // price is supplied for them — the store keeps its existing behavior.
    let single_price = (payment_type == "single").then(|| {
        let rules = collection_pricing_rules(api);
        let fixed = collection_user_fixed_price(api, &user_id);
        booking::pricing::effective_slot_price(booking::time::hour_of(slot_ms), &rules, fixed)
    });

    match store.create_booking_priced(
        &user_id,
        slot_ms,
        payment_type,
        ref_id,
        notes,
        single_price,
        now,
    ) {
        Ok(id) => json(
            200,
            &Value::Object(vec![(
                "booking".into(),
                Value::Object(vec![("bookingId".into(), Value::Str(id))]),
            )]),
        ),
        Err(e) => json(400, &error_value(&e)),
    }
}

/// `GET /api/bookings?userId=X` lists a user's bookings;
/// `DELETE /api/bookings?id=B&userId=X` cancels one.
fn api_bookings(store: &BookingStore, req: &Request, auth: &auth::State) -> Response {
    let q = query_pairs(req);
    match req.method {
        Method::Get => {
            let Some(user_id) = resolve_user_id(req, None, auth) else {
                return json(401, &error_value("Unauthorized"));
            };
            let list: Vec<Value> = store
                .bookings_for_user(&user_id)
                .iter()
                .map(booking_value)
                .collect();
            json(
                200,
                &Value::Object(vec![("bookings".into(), Value::Array(list))]),
            )
        }
        Method::Delete => {
            let Some(user_id) = resolve_user_id(req, None, auth) else {
                return json(401, &error_value("Unauthorized"));
            };
            let Some(id) = field(&q, "id").filter(|s| !s.is_empty()) else {
                return json(400, &error_value("id is required"));
            };
            match store.cancel_booking(id, &user_id, now_ms()) {
                Ok(()) => json(
                    200,
                    &Value::Object(vec![("cancelled".into(), Value::Bool(true))]),
                ),
                Err(e) => json(400, &error_value(&e)),
            }
        }
        _ => json(405, &error_value("method not allowed")),
    }
}

/// Subscription-member sharing API. The `path` is the full request path under
/// `/api/user-subscriptions/`. We parse the subscription id and (optionally) a
/// member id out of it, then route by method:
///
/// * `GET    /api/user-subscriptions/:id/members`            — list members
/// * `POST   /api/user-subscriptions/:id/members`            — invite by phone
/// * `DELETE /api/user-subscriptions/:id/members/:memberId`  — remove a member
///
/// Every route is auth-gated (401 without a session). Invite/remove are
/// owner-only — that guard lives in the store and surfaces as a 403/400 error.
fn api_subscription_members(
    store: &BookingStore,
    path: &str,
    req: &Request,
    auth: &auth::State,
) -> Response {
    // `<id>/members` or `<id>/members/<memberId>`
    let rest = slug_of(path, "/api/user-subscriptions/");
    let Some((sub_id, tail)) = rest.split_once("/members") else {
        return json(404, &error_value("not found"));
    };
    let sub_id = sub_id.trim_end_matches('/');
    let member_id = tail.trim_start_matches('/').trim_end_matches('/');
    if sub_id.is_empty() {
        return json(404, &error_value("not found"));
    }

    let Some(user_id) = resolve_user_id(req, None, auth) else {
        return json(401, &error_value("Unauthorized"));
    };

    match req.method {
        Method::Get => {
            // Any owner/active member may view the roster.
            if !store.can_use_subscription(&user_id, sub_id) {
                return json(
                    403,
                    &error_value("Áskrift fannst ekki eða er ekki tengd þessum notanda"),
                );
            }
            let members = store.list_subscription_members(sub_id);
            let usage = store
                .shared_subscription_usage(sub_id, now_ms())
                .map(|u| usage_value(&u))
                .unwrap_or(Value::Null);
            json(
                200,
                &Value::Object(vec![
                    ("members".into(), members_array(&members)),
                    ("usage".into(), usage),
                ]),
            )
        }
        Method::Post => {
            let body = akurai_json::parse(&req.body_str()).unwrap_or(Value::Null);
            let phone = body.get("phone").and_then(Value::as_str).unwrap_or("");
            match store.invite_subscription_member(&user_id, sub_id, phone, now_ms()) {
                Ok(member) => {
                    let members = store.list_subscription_members(sub_id);
                    json(
                        201,
                        &Value::Object(vec![
                            ("member".into(), member_value(&member_to_view(&member))),
                            ("members".into(), members_array(&members)),
                        ]),
                    )
                }
                Err(e) => json(400, &error_value(&e)),
            }
        }
        Method::Delete => {
            if member_id.is_empty() {
                return json(400, &error_value("memberId is required"));
            }
            match store.remove_subscription_member(&user_id, sub_id, member_id, now_ms()) {
                Ok(_member) => {
                    let members = store.list_subscription_members(sub_id);
                    json(
                        200,
                        &Value::Object(vec![("members".into(), members_array(&members))]),
                    )
                }
                Err(e) => json(400, &error_value(&e)),
            }
        }
        _ => json(405, &error_value("method not allowed")),
    }
}

/// Serialize the shared daily-usage summary the calendar shows the group.
fn usage_value(u: &booking::subscription_sharing::SharedUsageSummary) -> Value {
    Value::Object(vec![
        ("used".into(), Value::Int(u.used)),
        ("limit".into(), Value::Int(u.limit)),
        ("remaining".into(), Value::Int(u.remaining)),
        ("exhausted".into(), Value::Bool(u.exhausted)),
        ("label".into(), Value::Str(u.label.clone())),
    ])
}

/// A JSON array of member views.
fn members_array(members: &[booking::subscription_sharing::ListMemberView]) -> Value {
    Value::Array(members.iter().map(member_value).collect())
}

/// Serialize one member view to JSON, masking the invited phone for display.
fn member_value(m: &booking::subscription_sharing::ListMemberView) -> Value {
    let opt_str = |o: &Option<String>| o.clone().map(Value::Str).unwrap_or(Value::Null);
    let opt_int = |o: Option<i64>| o.map(Value::Int).unwrap_or(Value::Null);
    let masked = m
        .invited_phone
        .as_deref()
        .and_then(|p| booking::subscription_sharing::mask_subscription_phone(p).ok());
    Value::Object(vec![
        ("id".into(), Value::Str(m.id.clone())),
        ("userId".into(), opt_str(&m.user_id)),
        ("name".into(), opt_str(&m.name)),
        ("phone".into(), opt_str(&m.phone)),
        ("invitedPhone".into(), opt_str(&m.invited_phone)),
        (
            "invitedPhoneMasked".into(),
            masked.map(Value::Str).unwrap_or(Value::Null),
        ),
        ("role".into(), Value::Str(m.role.clone())),
        ("status".into(), Value::Str(m.status.clone())),
        (
            "statusLabel".into(),
            Value::Str(booking::subscription_sharing::get_member_status_label(&m.status).into()),
        ),
        ("invitedAt".into(), Value::Int(m.invited_at)),
        ("acceptedAt".into(), opt_int(m.accepted_at)),
    ])
}

/// Adapt a stored member record into the view shape the API serializes.
fn member_to_view(
    m: &booking::subscription_sharing::UserSubscriptionMember,
) -> booking::subscription_sharing::ListMemberView {
    booking::subscription_sharing::ListMemberView {
        id: m.id.clone(),
        user_id: m.user_id.clone(),
        name: None,
        phone: None,
        invited_phone: m.invited_phone.clone(),
        role: m.role.clone(),
        status: m.status.clone(),
        invited_at: m.invited_at,
        accepted_at: m.accepted_at,
    }
}
/// Serialize availability into the `{ availability: [...] }` JSON the source
/// route returns.
fn availability_value(days: &[booking::DayAvailability]) -> Value {
    let arr = days
        .iter()
        .map(|day| {
            let slots = day
                .slots
                .iter()
                .map(|s| {
                    Value::Object(vec![
                        ("hour".into(), Value::Int(s.hour)),
                        ("startsAt".into(), Value::Str(s.starts_at.clone())),
                        ("price".into(), Value::Int(s.price)),
                        ("status".into(), Value::Str(s.status.clone())),
                    ])
                })
                .collect();
            Value::Object(vec![
                ("date".into(), Value::Str(day.date.clone())),
                ("slots".into(), Value::Array(slots)),
            ])
        })
        .collect();
    Value::Object(vec![("availability".into(), Value::Array(arr))])
}

/// Serialize one booking record to JSON (camelCase, mirroring the source API).
fn booking_value(b: &booking::Booking) -> Value {
    let opt_str = |o: &Option<String>| o.clone().map(Value::Str).unwrap_or(Value::Null);
    let opt_int = |o: Option<i64>| o.map(Value::Int).unwrap_or(Value::Null);
    Value::Object(vec![
        ("id".into(), Value::Str(b.id.clone())),
        ("userId".into(), Value::Str(b.user_id.clone())),
        (
            "startsAt".into(),
            Value::Str(booking::time::iso_string(b.starts_at)),
        ),
        ("status".into(), Value::Str(b.status.clone())),
        ("paymentType".into(), Value::Str(b.payment_type.clone())),
        ("pricePaid".into(), opt_int(b.price_paid)),
        ("userPackageId".into(), opt_str(&b.user_package_id)),
        (
            "userSubscriptionId".into(),
            opt_str(&b.user_subscription_id),
        ),
        ("notes".into(), opt_str(&b.notes)),
    ])
}

