// Admin product CRUD on the COLLECTIONS `products` collection — the same store
// the shop + admin LIST pages read, so writes here round-trip into those lists.
fn api_admin_products(api: &CollectionsApi, req: &Request, path_id: Option<&str>) -> Response {
    match req.method {
        Method::Get => {
            if let Some(id) = path_id {
                let Ok(id) = id.parse::<i64>() else {
                    return json(400, &error_value("invalid id"));
                };
                return match api.record_by_id("products", id) {
                    Some(record) => json(
                        200,
                        &Value::Object(vec![(
                            "product".into(),
                            product_value_from_record(&record, &collection_category_names(api)),
                        )]),
                    ),
                    None => json(404, &error_value("not found")),
                };
            }
            json(
                200,
                &Value::Object(vec![(
                    "products".into(),
                    Value::Array(collection_product_values(api, false)),
                )]),
            )
        }
        Method::Post => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let Some(name) = str_field(&body, "name") else {
                return json(400, &error_value("name required"));
            };
            let Some(price) = int_field(&body, "price").filter(|p| *p >= 0) else {
                return json(400, &error_value("valid price required"));
            };
            let category = match admin_category_relation(&body) {
                Ok(c) => c,
                Err(r) => return r,
            };
            let now = now_ms();
            let mut input = vec![
                ("name".into(), Value::Str(name.to_string())),
                ("price".into(), Value::Int(price)),
                (
                    "active".into(),
                    Value::Bool(bool_field(&body, "active").unwrap_or(true)),
                ),
                ("position".into(), Value::Int(0)),
                ("created_at".into(), Value::Int(now)),
                ("updated_at".into(), Value::Int(now)),
            ];
            if let Some(desc) = str_field(&body, "description") {
                input.push(("description".into(), Value::Str(desc.to_string())));
            }
            if let Some(img) =
                str_field(&body, "imageUrl").or_else(|| str_field(&body, "image_url"))
            {
                input.push(("image_url".into(), Value::Str(img.to_string())));
            }
            if let Some(cat) = category {
                input.push(("category".into(), Value::Int(cat)));
            }
            match api.create_record("products", Value::Object(input)) {
                Ok(record) => json(
                    201,
                    &Value::Object(vec![(
                        "product".into(),
                        product_value_from_record(&record, &collection_category_names(api)),
                    )]),
                ),
                Err((status, msg)) => json(status, &error_value(&msg)),
            }
        }
        Method::Put => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let query_id = query_id(req);
            let Some(id) = path_id
                .or_else(|| str_field(&body, "id"))
                .or(query_id.as_deref())
            else {
                return json(400, &error_value("id required"));
            };
            let Ok(id) = id.parse::<u64>() else {
                return json(400, &error_value("invalid id"));
            };
            let mut patch: Vec<(String, Value)> = Vec::new();
            if let Some(name) = str_field(&body, "name") {
                patch.push(("name".into(), Value::Str(name.to_string())));
            }
            if let Some(price) = int_field(&body, "price") {
                if price < 0 {
                    return json(400, &error_value("valid price required"));
                }
                patch.push(("price".into(), Value::Int(price)));
            }
            if field_present(&body, "description") {
                patch.push((
                    "description".into(),
                    opt_str_value(str_field(&body, "description")),
                ));
            }
            if field_present(&body, "imageUrl") || field_present(&body, "image_url") {
                let img = str_field(&body, "imageUrl").or_else(|| str_field(&body, "image_url"));
                patch.push(("image_url".into(), opt_str_value(img)));
            }
            if field_present(&body, "categoryId") || field_present(&body, "category_id") {
                let cat = match admin_category_relation(&body) {
                    Ok(c) => c,
                    Err(r) => return r,
                };
                patch.push((
                    "category".into(),
                    cat.map(Value::Int).unwrap_or(Value::Null),
                ));
            }
            if let Some(active) = bool_field(&body, "active") {
                patch.push(("active".into(), Value::Bool(active)));
            }
            if let Some(position) = int_field(&body, "position") {
                patch.push(("position".into(), Value::Int(position)));
            }
            patch.push(("updated_at".into(), Value::Int(now_ms())));
            match api.update_record("products", id, Value::Object(patch)) {
                Ok(Some(record)) => json(
                    200,
                    &Value::Object(vec![(
                        "product".into(),
                        product_value_from_record(&record, &collection_category_names(api)),
                    )]),
                ),
                Ok(None) => json(404, &error_value("not found")),
                Err((status, msg)) => json(status, &error_value(&msg)),
            }
        }
        Method::Delete => {
            let body = body_json(req).ok();
            let query_id = query_id(req);
            let Some(id) = path_id
                .or_else(|| body.as_ref().and_then(|b| str_field(b, "id")))
                .or(query_id.as_deref())
            else {
                return json(400, &error_value("id required"));
            };
            let Ok(id) = id.parse::<u64>() else {
                return json(400, &error_value("invalid id"));
            };
            match api.delete_record("products", id) {
                Ok(true) => json(200, &Value::Object(vec![("ok".into(), Value::Bool(true))])),
                Ok(false) => json(404, &error_value("not found")),
                Err((status, msg)) => json(status, &error_value(&msg)),
            }
        }
        _ => json(405, &error_value("method not allowed")),
    }
}

/// Parse the admin product form's `categoryId` (or snake_case `category_id`)
/// into a relation id: `None` for an absent/blank selection (no category), or
/// `Some(id)`. A non-numeric value is a 400 error.
fn admin_category_relation(body: &Value) -> Result<Option<i64>, Response> {
    match str_field(body, "categoryId").or_else(|| str_field(body, "category_id")) {
        None => Ok(None),
        Some(s) => s
            .parse::<i64>()
            .map(Some)
            .map_err(|_| json(400, &error_value("invalid category"))),
    }
}

// Admin category CRUD on the COLLECTIONS `product_categories` collection.
fn api_admin_categories(api: &CollectionsApi, req: &Request, path_id: Option<&str>) -> Response {
    match req.method {
        Method::Get => {
            if let Some(id) = path_id {
                let Ok(id) = id.parse::<i64>() else {
                    return json(400, &error_value("invalid id"));
                };
                return match api.record_by_id("product_categories", id) {
                    Some(record) => json(
                        200,
                        &Value::Object(vec![(
                            "category".into(),
                            category_value_from_record(&record),
                        )]),
                    ),
                    None => json(404, &error_value("not found")),
                };
            }
            json(
                200,
                &Value::Object(vec![(
                    "categories".into(),
                    Value::Array(collection_category_values(api)),
                )]),
            )
        }
        Method::Post => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let Some(name) = str_field(&body, "name") else {
                return json(400, &error_value("name required"));
            };
            // Slug: the supplied value, or one derived from the name (mirrors the
            // source's auto-slug). UNIQUE in the source — enforced here too.
            let slug = match str_field(&body, "slug") {
                Some(s) => shop::slugify(s),
                None => shop::slugify(name),
            };
            if slug.is_empty() {
                return json(400, &error_value("valid slug required"));
            }
            if category_slug_taken(api, &slug, None) {
                return json(400, &error_value("slug already exists"));
            }
            let now = now_ms();
            let mut input = vec![
                ("name".into(), Value::Str(name.to_string())),
                ("slug".into(), Value::Str(slug)),
                (
                    "position".into(),
                    Value::Int(int_field(&body, "position").unwrap_or(0)),
                ),
                (
                    "active".into(),
                    Value::Bool(bool_field(&body, "active").unwrap_or(true)),
                ),
                ("created_at".into(), Value::Int(now)),
                ("updated_at".into(), Value::Int(now)),
            ];
            if let Some(desc) = str_field(&body, "description") {
                input.push(("description".into(), Value::Str(desc.to_string())));
            }
            match api.create_record("product_categories", Value::Object(input)) {
                Ok(record) => json(
                    201,
                    &Value::Object(vec![(
                        "category".into(),
                        category_value_from_record(&record),
                    )]),
                ),
                Err((status, msg)) => json(status, &error_value(&msg)),
            }
        }
        Method::Put => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let query_id = query_id(req);
            let Some(id) = path_id
                .or_else(|| str_field(&body, "id"))
                .or(query_id.as_deref())
            else {
                return json(400, &error_value("id required"));
            };
            let Ok(id) = id.parse::<u64>() else {
                return json(400, &error_value("invalid id"));
            };
            let mut patch: Vec<(String, Value)> = Vec::new();
            if let Some(name) = str_field(&body, "name") {
                patch.push(("name".into(), Value::Str(name.to_string())));
            }
            if field_present(&body, "slug") {
                let Some(raw) = str_field(&body, "slug") else {
                    return json(400, &error_value("valid slug required"));
                };
                let slug = shop::slugify(raw);
                if slug.is_empty() {
                    return json(400, &error_value("valid slug required"));
                }
                if category_slug_taken(api, &slug, Some(id as i64)) {
                    return json(400, &error_value("slug already exists"));
                }
                patch.push(("slug".into(), Value::Str(slug)));
            }
            if field_present(&body, "description") {
                patch.push((
                    "description".into(),
                    opt_str_value(str_field(&body, "description")),
                ));
            }
            if let Some(position) = int_field(&body, "position") {
                patch.push(("position".into(), Value::Int(position)));
            }
            if let Some(active) = bool_field(&body, "active") {
                patch.push(("active".into(), Value::Bool(active)));
            }
            patch.push(("updated_at".into(), Value::Int(now_ms())));
            match api.update_record("product_categories", id, Value::Object(patch)) {
                Ok(Some(record)) => json(
                    200,
                    &Value::Object(vec![(
                        "category".into(),
                        category_value_from_record(&record),
                    )]),
                ),
                Ok(None) => json(404, &error_value("not found")),
                Err((status, msg)) => json(status, &error_value(&msg)),
            }
        }
        Method::Delete => {
            let body = body_json(req).ok();
            let query_id = query_id(req);
            let Some(id) = path_id
                .or_else(|| body.as_ref().and_then(|b| str_field(b, "id")))
                .or(query_id.as_deref())
            else {
                return json(400, &error_value("id required"));
            };
            let Ok(id) = id.parse::<u64>() else {
                return json(400, &error_value("invalid id"));
            };
            // Mirror the source FK `ON DELETE SET NULL`: clear the relation on any
            // product still pointing at this category before removing it.
            for product in api.records("products") {
                if product.get("category").and_then(Value::as_i64) == Some(id as i64) {
                    if let Some(pid) = product.get("id").and_then(Value::as_i64) {
                        let _ = api.update_record(
                            "products",
                            pid as u64,
                            Value::Object(vec![("category".into(), Value::Null)]),
                        );
                    }
                }
            }
            match api.delete_record("product_categories", id) {
                Ok(true) => json(200, &Value::Object(vec![("ok".into(), Value::Bool(true))])),
                Ok(false) => json(404, &error_value("not found")),
                Err((status, msg)) => json(status, &error_value(&msg)),
            }
        }
        _ => json(405, &error_value("method not allowed")),
    }
}

/// Whether a `product_categories` slug is already used by a record other than
/// `except_id` (the source enforces a UNIQUE slug; collections do not).
fn category_slug_taken(api: &CollectionsApi, slug: &str, except_id: Option<i64>) -> bool {
    api.records("product_categories").iter().any(|c| {
        c.get("slug").and_then(Value::as_str) == Some(slug)
            && c.get("id").and_then(Value::as_i64) != except_id
    })
}

fn api_cart(store: &CartStore, req: &Request, auth: &auth::State) -> Response {
    if req.method != Method::Get {
        return json(405, &error_value("method not allowed"));
    }
    let user = auth.current_user(req);
    let effective_id = user
        .as_ref()
        .map(|u| user_cart_id(&u.email))
        .or_else(|| cart::cookie_cart_id(req));
    match store.get_or_create_open(effective_id.as_deref(), now_ms()) {
        Ok((summary, created)) => {
            let set = created && user.is_none();
            cart_json(200, &summary, set)
        }
        Err(e) => json(500, &error_value(&e)),
    }
}

fn api_cart_items(
    booking_store: &BookingStore,
    collections_api: &CollectionsApi,
    cart_store: &CartStore,
    req: &Request,
    path_id: Option<&str>,
    auth: &auth::State,
) -> Response {
    let user = auth.current_user(req);
    let effective_id = user
        .as_ref()
        .map(|u| user_cart_id(&u.email))
        .or_else(|| cart::cookie_cart_id(req));
    let (summary, created) = match cart_store.get_or_create_open(effective_id.as_deref(), now_ms())
    {
        Ok(v) => v,
        Err(e) => return json(500, &error_value(&e)),
    };
    let set_cookie = created && user.is_none();
    match req.method {
        Method::Post => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let item = match resolve_cart_item(booking_store, collections_api, &body, now_ms()) {
                Ok(item) => item,
                Err((status, e)) => return json(status, &error_value(&e)),
            };
            match cart_store.add_item(&summary.id, item, now_ms()) {
                Ok(next) => cart_json(201, &next, set_cookie),
                Err(e) => json(400, &error_value(&e)),
            }
        }
        Method::Put | Method::Patch => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let query_id = query_id(req);
            let id = path_id
                .or_else(|| str_field(&body, "id"))
                .or(query_id.as_deref());
            let Some(id) = id else {
                return json(400, &error_value("id required"));
            };
            let Some(quantity) = int_field(&body, "quantity") else {
                return json(400, &error_value("quantity must be a non-negative number"));
            };
            match cart_store.update_quantity(&summary.id, id, quantity, now_ms()) {
                Ok(next) => cart_json(200, &next, set_cookie),
                Err(e) if e == "item not found" => json(404, &error_value(&e)),
                Err(e) => json(400, &error_value(&e)),
            }
        }
        Method::Delete => {
            let body = body_json(req).ok();
            let query_id = query_id(req);
            let id = path_id
                .or_else(|| body.as_ref().and_then(|b| str_field(b, "id")))
                .or(query_id.as_deref());
            let Some(id) = id else {
                return json(400, &error_value("id required"));
            };
            match cart_store.remove_item(&summary.id, id, now_ms()) {
                Ok(next) => cart_json(200, &next, set_cookie),
                Err(e) => json(400, &error_value(&e)),
            }
        }
        _ => json(405, &error_value("method not allowed")),
    }
}

fn api_cart_items_bulk(
    booking_store: &BookingStore,
    collections_api: &CollectionsApi,
    cart_store: &CartStore,
    req: &Request,
    auth: &auth::State,
) -> Response {
    if req.method != Method::Post {
        return json(405, &error_value("method not allowed"));
    }
    let body = match body_json(req) {
        Ok(v) => v,
        Err(r) => return r,
    };
    let Some(Value::Array(items)) = body.get("items") else {
        return json(400, &error_value("items[] required"));
    };
    if items.is_empty() {
        return json(400, &error_value("items[] required"));
    }
    if items.len() > 50 {
        return json(400, &error_value("too many items"));
    }
    let user = auth.current_user(req);
    let effective_id = user
        .as_ref()
        .map(|u| user_cart_id(&u.email))
        .or_else(|| cart::cookie_cart_id(req));
    let (mut summary, created) =
        match cart_store.get_or_create_open(effective_id.as_deref(), now_ms()) {
            Ok(v) => v,
            Err(e) => return json(500, &error_value(&e)),
        };
    for raw in items {
        if let Ok(item) = resolve_cart_item(booking_store, collections_api, raw, now_ms()) {
            match cart_store.add_item(&summary.id, item, now_ms()) {
                Ok(next) => summary = next,
                Err(_) => continue,
            }
        }
    }
    cart_json(201, &summary, created && user.is_none())
}

fn resolve_cart_item(
    booking_store: &BookingStore,
    collections_api: &CollectionsApi,
    body: &Value,
    now: i64,
) -> Result<cart::ResolvedItem, (u16, String)> {
    let item_type = str_field(body, "type").ok_or((400, "type required".to_string()))?;
    match item_type {
        "product" => {
            let ref_id = str_field(body, "refId").ok_or((400, "refId required".to_string()))?;
            let id = ref_id
                .parse::<i64>()
                .map_err(|_| (400, "invalid product id".to_string()))?;
            let product = collections_api
                .record_by_id("products", id)
                .filter(|p| p.get("active").and_then(Value::as_bool) != Some(false))
                .ok_or((404, "product not found".to_string()))?;
            let name = product
                .get("name")
                .and_then(Value::as_str)
                .unwrap_or("Vara")
                .to_string();
            let price = product.get("price").and_then(Value::as_i64).unwrap_or(0);
            Ok(cart::ResolvedItem {
                item_type: "product".into(),
                ref_id: id.to_string(),
                name_snapshot: name,
                unit_price: price,
                quantity: int_field(body, "quantity").unwrap_or(1).max(1),
                metadata: Value::Object(vec![]),
            })
        }
        "gift_card" => resolve_gift_card_item(body),
        "slot" => resolve_slot_item(booking_store, collections_api, body, now),
        "package" | "subscription" => resolve_snapshot_item(body, item_type),
        _ => Err((400, "invalid type".into())),
    }
}

fn resolve_gift_card_item(body: &Value) -> Result<cart::ResolvedItem, (u16, String)> {
    const MIN: i64 = 1000;
    const MAX: i64 = 500_000;
    let amount = int_field(body, "amount").ok_or((
        400,
        "Upphæð gjafabréfs verður að vera á bilinu 1.000-500.000 kr.".to_string(),
    ))?;
    if !(MIN..=MAX).contains(&amount) {
        return Err((
            400,
            "Upphæð gjafabréfs verður að vera á bilinu 1.000-500.000 kr.".into(),
        ));
    }
    let mut meta = vec![("amount".into(), Value::Int(amount))];
    for key in [
        "recipientName",
        "recipientEmail",
        "message",
        "deliveryAt",
        "theme",
    ] {
        if let Some(value) = str_field(body, key).filter(|s| !s.trim().is_empty()) {
            meta.push((key.into(), Value::Str(value.trim().to_string())));
        }
    }
    Ok(cart::ResolvedItem {
        item_type: "gift_card".into(),
        ref_id: format!("gift-{}", now_ms()),
        name_snapshot: format!("Gjafabréf · {}", shop::format_isk(amount)),
        unit_price: amount,
        quantity: 1,
        metadata: Value::Object(meta),
    })
}

fn resolve_slot_item(
    booking_store: &BookingStore,
    api: &CollectionsApi,
    body: &Value,
    now: i64,
) -> Result<cart::ResolvedItem, (u16, String)> {
    let ref_id = str_field(body, "refId").ok_or((400, "refId required".to_string()))?;
    let slot_ms = booking::time::parse_instant(ref_id).ok_or((400, "invalid slot".to_string()))?;
    if slot_ms < now {
        return Err((400, "slot is in the past".into()));
    }
    let day = booking::time::day_start(slot_ms);
    let available = booking_store
        .availability(day, 1, None, now)
        .iter()
        .flat_map(|d| d.slots.iter())
        .find(|s| s.starts_at == ref_id)
        .map(|s| s.status == "available")
        .unwrap_or(false);
    if !available {
        return Err((409, "slot already booked".into()));
    }
    let hour = booking::time::hour_of(slot_ms);
    // The charged snapshot comes from the collections pricing rules (the same
    // source `/api/slot-price` and the booking-create path use), so an admin
    // pricing change in collections is reflected in the cart and the fulfilled
    // booking. No per-user fixed price here — the cart can be anonymous.
    let unit_price = booking::pricing::slot_price(hour, &collection_pricing_rules(api));
    Ok(cart::ResolvedItem {
        item_type: "slot".into(),
        ref_id: ref_id.to_string(),
        name_snapshot: format!("{ref_id} kl. {hour:02}:00"),
        unit_price,
        quantity: 1,
        metadata: Value::Object(vec![
            ("startsAt".into(), Value::Str(ref_id.to_string())),
            ("hour".into(), Value::Int(hour)),
        ]),
    })
}

fn resolve_snapshot_item(
    body: &Value,
    item_type: &str,
) -> Result<cart::ResolvedItem, (u16, String)> {
    let ref_id = str_field(body, "refId").ok_or((400, "refId required".to_string()))?;
    let name = str_field(body, "nameSnapshot")
        .or_else(|| str_field(body, "name"))
        .ok_or((400, "nameSnapshot required".to_string()))?;
    let unit_price = int_field(body, "unitPrice")
        .or_else(|| int_field(body, "price"))
        .ok_or((400, "unitPrice required".to_string()))?;
    Ok(cart::ResolvedItem {
        item_type: item_type.to_string(),
        ref_id: ref_id.to_string(),
        name_snapshot: name.trim().to_string(),
        unit_price,
        quantity: if item_type == "subscription" {
            1
        } else {
            int_field(body, "quantity").unwrap_or(1).max(1)
        },
        metadata: body
            .get("metadata")
            .cloned()
            .unwrap_or_else(|| Value::Object(vec![])),
    })
}

/// Derive a stable, valid cart ID for an authenticated user.
/// Uses the email with non-alphanumeric chars mapped to dashes so it satisfies
/// `cart::valid_cart_id` (alphanumeric + dash, max 96 chars).
pub fn user_cart_id(email: &str) -> String {
    let slug: String = email
        .chars()
        .map(|c| if c.is_ascii_alphanumeric() { c } else { '-' })
        .collect::<String>()
        .trim_matches('-')
        .to_string();
    format!("u-{}", &slug[..slug.len().min(90)])
}

// ---- gift card API --------------------------------------------------------

/// Serialize a gift card to camelCase JSON (mirroring the source API). Includes
/// a formatted ISK label for `amount`/`balance` for direct template use.
fn giftcard_value(card: &giftcards::GiftCard) -> Value {
    let opt_str = |o: &Option<String>| o.clone().map(Value::Str).unwrap_or(Value::Null);
    let opt_int = |o: Option<i64>| o.map(Value::Int).unwrap_or(Value::Null);
    Value::Object(vec![
        ("id".into(), Value::Str(card.id.clone())),
        ("code".into(), Value::Str(card.code.clone())),
        ("amount".into(), Value::Int(card.amount)),
        (
            "amountLabel".into(),
            Value::Str(shop::format_isk(card.amount)),
        ),
        ("balance".into(), Value::Int(card.balance)),
        (
            "balanceLabel".into(),
            Value::Str(shop::format_isk(card.balance)),
        ),
        ("currency".into(), Value::Str(card.currency.clone())),
        ("status".into(), Value::Str(card.status.clone())),
        ("expiresAt".into(), opt_int(card.expires_at)),
        ("deliveryAt".into(), opt_int(card.delivery_at)),
        ("deliveredAt".into(), opt_int(card.delivered_at)),
        ("recipientEmail".into(), opt_str(&card.recipient_email)),
        ("recipientPhone".into(), opt_str(&card.recipient_phone)),
        ("recipientName".into(), opt_str(&card.recipient_name)),
        ("message".into(), opt_str(&card.message)),
        ("createdAt".into(), Value::Int(card.created_at)),
    ])
}

/// `POST /api/cart/gift-card/lookup` — public lookup of a code against the
/// active cart. Returns the card balance plus how much would apply to the cart
/// subtotal. Errors (not found / inactive / expired / depleted) return 200 with
/// `{ ok: false, reason }`, mirroring the source route.
fn api_giftcard_lookup(store: &GiftCardStore, cart_store: &CartStore, req: &Request) -> Response {
    if req.method != Method::Post {
        return json(405, &error_value("method not allowed"));
    }
    let body = body_json(req).unwrap_or(Value::Object(vec![]));
    let raw_code = body.get("code").and_then(Value::as_str).unwrap_or("");
    let code = GiftCardStore::normalize_code(raw_code);
    if code.is_empty() {
        return json(
            200,
            &Value::Object(vec![
                ("ok".into(), Value::Bool(false)),
                ("reason".into(), Value::Str("not_found".into())),
            ]),
        );
    }

    let card = match store.lookup(&code, now_ms()) {
        Ok(card) => card,
        Err(reason) => {
            return json(
                200,
                &Value::Object(vec![
                    ("ok".into(), Value::Bool(false)),
                    ("reason".into(), Value::Str(reason.as_str().into())),
                ]),
            );
        }
    };

    // Resolve the active cart subtotal (anonymous cookie cart or user cart).
    let effective_id = cart::cookie_cart_id(req);
    let subtotal = cart_store
        .get_or_create_open(effective_id.as_deref(), now_ms())
        .map(|(summary, _)| summary.subtotal)
        .unwrap_or(0);
    let applied = card.balance.min(subtotal);
    let remaining = subtotal - applied;

    json(
        200,
        &Value::Object(vec![
            ("ok".into(), Value::Bool(true)),
            (
                "card".into(),
                Value::Object(vec![
                    ("code".into(), Value::Str(card.code.clone())),
                    ("balance".into(), Value::Int(card.balance)),
                    (
                        "balanceLabel".into(),
                        Value::Str(shop::format_isk(card.balance)),
                    ),
                    ("currency".into(), Value::Str(card.currency.clone())),
                ]),
            ),
            ("cartSubtotal".into(), Value::Int(subtotal)),
            ("applied".into(), Value::Int(applied)),
            ("remaining".into(), Value::Int(remaining)),
        ]),
    )
}

/// `POST /api/cart/gift-card/redeem` — apply a gift card to the active cart.
///
/// Body: `{ "code": "GOLF-XXXX-XXXX-XXXX", "cartTotal": 15000 }`
///
/// Returns the applied amount, remaining card balance, and remaining cart total
/// so the checkout flow can display the discount breakdown to the user.
fn api_giftcard_redeem(store: &GiftCardStore, cart_store: &CartStore, req: &Request) -> Response {
    if req.method != Method::Post {
        return json(405, &error_value("method not allowed"));
    }
    let body = body_json(req).unwrap_or(Value::Object(vec![]));
    let raw_code = body.get("code").and_then(Value::as_str).unwrap_or("");
    let code = GiftCardStore::normalize_code(raw_code);
    if code.is_empty() {
        return json(
            400,
            &Value::Object(vec![
                ("ok".into(), Value::Bool(false)),
                ("reason".into(), Value::Str("not_found".into())),
            ]),
        );
    }

    // Use the provided cartTotal, or fall back to the active cart subtotal.
    let cart_total = match body.get("cartTotal").and_then(Value::as_i64) {
        Some(n) if n > 0 => n,
        _ => {
            let effective_id = cart::cookie_cart_id(req);
            cart_store
                .get_or_create_open(effective_id.as_deref(), now_ms())
                .map(|(summary, _)| summary.subtotal)
                .unwrap_or(0)
        }
    };

    let cart_id = body
        .get("cartId")
        .and_then(Value::as_str)
        .map(|s| s.to_string());

    match store.redeem(&code, cart_total, cart_id.as_deref(), None, now_ms()) {
        Ok(result) => json(
            200,
            &Value::Object(vec![
                ("ok".into(), Value::Bool(true)),
                ("giftCardId".into(), Value::Str(result.gift_card_id)),
                ("applied".into(), Value::Int(result.applied)),
                (
                    "appliedLabel".into(),
                    Value::Str(shop::format_isk(result.applied)),
                ),
                (
                    "remainingBalance".into(),
                    Value::Int(result.remaining_balance),
                ),
                (
                    "remainingCartTotal".into(),
                    Value::Int(result.remaining_cart_total),
                ),
            ]),
        ),
        Err(reason) => json(
            200,
            &Value::Object(vec![
                ("ok".into(), Value::Bool(false)),
                ("reason".into(), Value::Str(reason.as_str().into())),
            ]),
        ),
    }
}

/// `GET /api/admin/gift-cards` lists all cards (or one when an id is in the
/// path). `POST /api/admin/gift-cards` issues one or more cards (admin only;
/// gating is done by the caller). Supports bulk issuance via `count`.
fn api_admin_giftcards(store: &GiftCardStore, req: &Request, path_id: Option<&str>) -> Response {
    match req.method {
        Method::Get => {
            if let Some(id) = path_id {
                return match store.get_by_id(id) {
                    Some(card) => {
                        let redemptions: Vec<Value> = store
                            .redemptions_for_card(&card.id)
                            .iter()
                            .map(redemption_value)
                            .collect();
                        json(
                            200,
                            &Value::Object(vec![
                                ("card".into(), giftcard_value(&card)),
                                ("redemptions".into(), Value::Array(redemptions)),
                            ]),
                        )
                    }
                    None => json(404, &error_value("not found")),
                };
            }
            let cards: Vec<Value> = store.list_all().iter().map(giftcard_value).collect();
            json(
                200,
                &Value::Object(vec![("giftCards".into(), Value::Array(cards))]),
            )
        }
        Method::Post => {
            let body = match body_json(req) {
                Ok(v) => v,
                Err(r) => return r,
            };
            let Some(amount) = int_field(&body, "amount").filter(|n| *n > 0) else {
                return json(400, &error_value("amount must be a positive integer"));
            };
            // Optional recipient email validation (mirrors the source check).
            let recipient_email = str_field(&body, "recipientEmail");
            if let Some(email) = recipient_email {
                if !valid_email(email) {
                    return json(400, &error_value("invalid recipient email"));
                }
            }
            let now = now_ms();
            // Expiry/delivery must be in the future when set.
            let expires_at = int_field(&body, "expiresAt").filter(|n| *n > 0);
            if let Some(exp) = expires_at {
                if exp <= now {
                    return json(400, &error_value("expiresAt must be in the future"));
                }
            }
            let delivery_at = int_field(&body, "deliveryAt").filter(|n| *n > 0);
            let recipient_name = str_field(&body, "recipientName");
            let recipient_phone = str_field(&body, "recipientPhone");
            let message = str_field(&body, "message");
            let currency = str_field(&body, "currency");
            let theme = str_field(&body, "theme");

            // Bulk issuance: `count` cards (default 1, capped at 100).
            let count = int_field(&body, "count").unwrap_or(1).clamp(1, 100);
            let mut issued = Vec::new();
            for _ in 0..count {
                match store.issue(
                    IssueParams {
                        amount,
                        currency,
                        purchased_by_user_id: None,
                        cart_id: None,
                        recipient_email,
                        recipient_phone,
                        recipient_name,
                        message,
                        theme,
                        expires_at,
                        delivery_at,
                    },
                    now,
                ) {
                    Ok((id, code)) => issued.push(Value::Object(vec![
                        ("id".into(), Value::Str(id)),
                        ("code".into(), Value::Str(code)),
                    ])),
                    Err(e) => return json(500, &error_value(&e)),
                }
            }

            // Single issuance returns the card directly; bulk returns the list.
            if count == 1 {
                json(
                    201,
                    &Value::Object(vec![("giftCard".into(), issued.remove(0))]),
                )
            } else {
                json(
                    201,
                    &Value::Object(vec![("giftCards".into(), Value::Array(issued))]),
                )
            }
        }
        _ => json(405, &error_value("method not allowed")),
    }
}

/// Serialize one redemption record to camelCase JSON.
fn redemption_value(r: &giftcards::GiftCardRedemption) -> Value {
    let opt_str = |o: &Option<String>| o.clone().map(Value::Str).unwrap_or(Value::Null);
    Value::Object(vec![
        ("id".into(), Value::Str(r.id.clone())),
        ("giftCardId".into(), Value::Str(r.gift_card_id.clone())),
        ("cartId".into(), opt_str(&r.cart_id)),
        ("paymentId".into(), opt_str(&r.payment_id)),
        ("amount".into(), Value::Int(r.amount)),
        ("amountLabel".into(), Value::Str(shop::format_isk(r.amount))),
        ("redeemedAt".into(), Value::Int(r.redeemed_at)),
    ])
}

/// Minimal email shape check (mirrors the source `^[^\s@]+@[^\s@]+\.[^\s@]+$`).
fn valid_email(email: &str) -> bool {
    let mut parts = email.split('@');
    let (Some(local), Some(domain), None) = (parts.next(), parts.next(), parts.next()) else {
        return false;
    };
    !local.is_empty()
        && !local.contains(char::is_whitespace)
        && domain.contains('.')
        && !domain.contains(char::is_whitespace)
        && !domain.starts_with('.')
        && !domain.ends_with('.')
}

fn cart_json(status: u16, summary: &cart::CartSummary, set_cookie: bool) -> Response {
    let resp = json(
        status,
        &Value::Object(vec![("cart".into(), cart::cart_value(summary))]),
    );
    if set_cookie {
        resp.with_header("Set-Cookie", &cart::cookie_header(&summary.id))
    } else {
        resp
    }
}

fn body_json(req: &Request) -> Result<Value, Response> {
    akurai_json::parse(&req.body_str()).map_err(|_| json(400, &error_value("invalid JSON body")))
}

fn str_field<'a>(body: &'a Value, key: &str) -> Option<&'a str> {
    body.get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|s| !s.is_empty())
}

fn int_field(body: &Value, key: &str) -> Option<i64> {
    match body.get(key)? {
        Value::Int(n) => Some(*n),
        Value::Float(n) if n.is_finite() => Some(n.floor() as i64),
        _ => None,
    }
}

fn bool_field(body: &Value, key: &str) -> Option<bool> {
    body.get(key).and_then(Value::as_bool)
}

fn field_present(body: &Value, key: &str) -> bool {
    matches!(body, Value::Object(pairs) if pairs.iter().any(|(k, _)| k == key))
}

fn query_id(req: &Request) -> Option<String> {
    field(&query_pairs(req), "id")
        .filter(|s| !s.is_empty())
        .map(str::to_string)
}

