// ---- account (mínar síður) page -------------------------------------------

/// `GET /my` — the signed-in user's account dashboard.
///
/// Server-side auth gate: unauthenticated requests redirect to `/login` (the
/// page's own JS performs the same `/api/me` 401 → `/login` redirect once
/// loaded, but the server gate means an unauthenticated `curl /my` never even
/// renders the shell).
///
/// The user's **active subscriptions** are server-rendered here (their daily
/// limit + validity window), because the account page is the only consumer and
/// there is no standalone subscriptions API yet. Profile, packages, and bookings
/// are fetched client-side from `/api/me`, `/api/user-packages`, and
/// `/api/bookings`. A subscription is *active* when today's calendar day falls
/// inside its `[valid_from, valid_until]` window (see [`booking::subscription`]).
fn my_page(root: &Path, store: &BookingStore, auth: &auth::State, req: &Request) -> Response {
    let Some(user) = auth.current_user(req) else {
        return Response::new(302).with_header("Location", "/login");
    };

    let now = now_ms();
    let mut subs: Vec<Value> = Vec::new();
    let mut active_count = 0_i64;
    for sub in store.user_subscriptions_for_user(&user.email) {
        let is_active = booking::subscription::covers_date(sub.valid_from, sub.valid_until, now);
        if is_active {
            active_count += 1;
        }
        subs.push(Value::Object(vec![
            ("id".into(), Value::Str(sub.id)),
            ("isActive".into(), Value::Bool(is_active)),
            ("dailyLimit".into(), Value::Int(sub.daily_limit)),
            (
                "validFrom".into(),
                Value::Str(booking::time::date_string(sub.valid_from)),
            ),
            (
                "validUntil".into(),
                Value::Str(booking::time::date_string(sub.valid_until)),
            ),
        ]));
    }

    render(
        root,
        "my",
        vec![
            (
                "page_title".into(),
                Value::Str("Mínar síður — Golfsetrið Akureyri".into()),
            ),
            ("subscriptions".into(), Value::Array(subs)),
            (
                "active_subscriptions_count".into(),
                Value::Int(active_count),
            ),
        ],
        auth,
        req,
    )
}

// ---- collections-backed catalog + pricing reads (Phase 4A) ----------------
//
// Phase 4A points the catalog/config READ paths at the framework collections
// store (mounted from backend/collections.toml) instead of the hand-rolled
// `ShopStore`/booking pricing trees. These helpers adapt collection records
// (auto-int `id` + snake_case fields) into the template-facing Values the pages
// already expect. Cart/booking *writes* still use the hand-rolled stores.

/// A `Some(trimmed)` string Value, or `Null` for absent/blank text.
fn opt_str_value(s: Option<&str>) -> Value {
    match s.map(str::trim).filter(|x| !x.is_empty()) {
        Some(x) => Value::Str(x.to_string()),
        None => Value::Null,
    }
}

/// Sort catalog records (products/categories) by position, then created_at,
/// then name — matching the hand-rolled store's ordering.
fn sort_catalog(records: &mut [Value]) {
    records.sort_by(|a, b| {
        let key = |v: &Value| {
            (
                v.get("position").and_then(Value::as_i64).unwrap_or(0),
                v.get("created_at").and_then(Value::as_i64).unwrap_or(0),
                v.get("name")
                    .and_then(Value::as_str)
                    .unwrap_or("")
                    .to_string(),
            )
        };
        key(a).cmp(&key(b))
    });
}

/// Map of `product_categories` record id -> category name.
fn collection_category_names(api: &CollectionsApi) -> std::collections::HashMap<i64, String> {
    api.records("product_categories")
        .into_iter()
        .filter_map(|c| {
            let id = c.get("id").and_then(Value::as_i64)?;
            let name = c.get("name").and_then(Value::as_str)?.to_string();
            Some((id, name))
        })
        .collect()
}

/// Adapt a `products` collection record into the template shape. `category` is
/// a relation id resolved to a name via `cat_names`.
fn product_value_from_record(
    p: &Value,
    cat_names: &std::collections::HashMap<i64, String>,
) -> Value {
    let price = p.get("price").and_then(Value::as_i64).unwrap_or(0);
    let category_id = p.get("category").and_then(Value::as_i64);
    let category_name = category_id.and_then(|id| cat_names.get(&id)).cloned();
    let image_url = p.get("image_url").and_then(Value::as_str);
    let display_image_url = image_url
        .and_then(non_empty)
        .or_else(|| fallback_product_image_url(p, category_name.as_deref()));
    Value::Object(vec![
        (
            "id".into(),
            Value::Int(p.get("id").and_then(Value::as_i64).unwrap_or(0)),
        ),
        (
            "name".into(),
            Value::Str(
                p.get("name")
                    .and_then(Value::as_str)
                    .unwrap_or("")
                    .to_string(),
            ),
        ),
        (
            "description".into(),
            opt_str_value(p.get("description").and_then(Value::as_str)),
        ),
        ("price".into(), Value::Int(price)),
        ("priceLabel".into(), Value::Str(format_isk(price))),
        ("imageUrl".into(), opt_str_value(image_url)),
        ("displayImageUrl".into(), opt_str_value(display_image_url)),
        (
            "categoryId".into(),
            category_id.map(Value::Int).unwrap_or(Value::Null),
        ),
        (
            "categoryName".into(),
            category_name.map(Value::Str).unwrap_or(Value::Null),
        ),
        (
            "active".into(),
            Value::Bool(p.get("active").and_then(Value::as_bool).unwrap_or(true)),
        ),
        (
            "position".into(),
            Value::Int(p.get("position").and_then(Value::as_i64).unwrap_or(0)),
        ),
        ("hasImage".into(), Value::Bool(display_image_url.is_some())),
        (
            "hasCustomImage".into(),
            Value::Bool(image_url.and_then(non_empty).is_some()),
        ),
    ])
}

fn non_empty(value: &str) -> Option<&str> {
    let value = value.trim();
    (!value.is_empty()).then_some(value)
}

fn fallback_product_image_url<'a>(p: &Value, category_name: Option<&str>) -> Option<&'a str> {
    let name = p
        .get("name")
        .and_then(Value::as_str)
        .unwrap_or("")
        .to_lowercase();
    if name.contains("golfhanski") || category_name == Some("Golfvara") {
        Some("/assets/products/golf-glove.webp")
    } else if category_name == Some("Drykkur") {
        Some("/assets/products/drinks-snacks.webp")
    } else {
        None
    }
}

/// All products from the collections store, sorted, optionally active-only, as
/// template Values.
fn collection_product_values(api: &CollectionsApi, active_only: bool) -> Vec<Value> {
    let cat_names = collection_category_names(api);
    let mut products = api.records("products");
    sort_catalog(&mut products);
    products
        .into_iter()
        .filter(|p| !active_only || p.get("active").and_then(Value::as_bool).unwrap_or(true))
        .map(|p| product_value_from_record(&p, &cat_names))
        .collect()
}

/// Adapt a `product_categories` collection record into the template shape.
fn category_value_from_record(c: &Value) -> Value {
    let s = |k: &str| c.get(k).and_then(Value::as_str).unwrap_or("").to_string();
    let active = c.get("active").and_then(Value::as_bool).unwrap_or(true);
    Value::Object(vec![
        (
            "id".into(),
            Value::Int(c.get("id").and_then(Value::as_i64).unwrap_or(0)),
        ),
        ("name".into(), Value::Str(s("name"))),
        ("slug".into(), Value::Str(s("slug"))),
        (
            "description".into(),
            opt_str_value(c.get("description").and_then(Value::as_str)),
        ),
        (
            "position".into(),
            Value::Int(c.get("position").and_then(Value::as_i64).unwrap_or(0)),
        ),
        ("active".into(), Value::Bool(active)),
        ("inactive".into(), Value::Bool(!active)),
    ])
}

/// All product categories from the collections store, sorted, as template Values.
fn collection_category_values(api: &CollectionsApi) -> Vec<Value> {
    let mut cats = api.records("product_categories");
    sort_catalog(&mut cats);
    cats.iter().map(category_value_from_record).collect()
}

/// Active pricing rules from the `pricing_rules` collection, in ascending-id
/// (insertion) order so rule precedence matches the source seed. A missing
/// `active` is treated as `true` (the source column default).
fn collection_pricing_rules(api: &CollectionsApi) -> Vec<booking::pricing::PricingRule> {
    let mut records = api.records("pricing_rules");
    records.sort_by_key(|r| r.get("id").and_then(Value::as_i64).unwrap_or(0));
    records
        .into_iter()
        .filter(|r| r.get("active").and_then(Value::as_bool).unwrap_or(true))
        .filter_map(|r| {
            Some(booking::pricing::PricingRule {
                name: r
                    .get("name")
                    .and_then(Value::as_str)
                    .unwrap_or("")
                    .to_string(),
                start_hour: r.get("start_hour").and_then(Value::as_i64)?,
                end_hour: r.get("end_hour").and_then(Value::as_i64)?,
                price: r.get("price").and_then(Value::as_i64).unwrap_or(0),
            })
        })
        .collect()
}

/// A business user's `fixed_price` override from the `users` collection, keyed
/// by email then phone (both unique in the source).
fn collection_user_fixed_price(api: &CollectionsApi, user_id: &str) -> Option<i64> {
    api.find_by("users", "email", user_id)
        .or_else(|| api.find_by("users", "phone", user_id))
        .and_then(|u| u.get("fixed_price").and_then(Value::as_i64))
}

// ---- shop + cart pages ----------------------------------------------------

fn shop_page(
    root: &Path,
    api: &CollectionsApi,
    cart_store: &CartStore,
    auth: &auth::State,
    req: &Request,
) -> Response {
    let user = auth.current_user(req);
    let effective_id = user
        .as_ref()
        .map(|u| user_cart_id(&u.email))
        .or_else(|| cart::cookie_cart_id(req));
    let (cart_value, cart_id, item_count, subtotal_label, created) =
        match cart_store.get_or_create_open(effective_id.as_deref(), now_ms()) {
            Ok((summary, created)) => (
                cart::cart_value(&summary),
                Some(summary.id),
                summary.item_count,
                shop::format_isk(summary.subtotal),
                created,
            ),
            Err(_) => (Value::Object(vec![]), None, 0, shop::format_isk(0), false),
        };

    let mut resp = render(
        root,
        "shop",
        vec![
            (
                "page_title".into(),
                Value::Str("Verslun — Golfsetrið Akureyri".into()),
            ),
            (
                "products".into(),
                Value::Array(collection_product_values(api, true)),
            ),
            (
                "categories".into(),
                Value::Array(collection_category_values(api)),
            ),
            ("cart".into(), cart_value),
            ("cart_item_count".into(), Value::Int(item_count)),
            (
                "cart_item_count_label".into(),
                Value::Str(item_count.to_string()),
            ),
            ("cart_has_items".into(), Value::Bool(item_count > 0)),
            ("cart_subtotal_label".into(), Value::Str(subtotal_label)),
        ],
        auth,
        req,
    );
    if created && user.is_none() {
        if let Some(cart_id) = cart_id {
            resp = resp.with_header("Set-Cookie", &cart::cookie_header(&cart_id));
        }
    }
    resp
}

fn cart_page(root: &Path, store: &CartStore, req: &Request, auth: &auth::State) -> Response {
    let user = auth.current_user(req);
    let effective_id = user
        .as_ref()
        .map(|u| user_cart_id(&u.email))
        .or_else(|| cart::cookie_cart_id(req));
    match store.get_or_create_open(effective_id.as_deref(), now_ms()) {
        Ok((summary, created)) => {
            let mut resp = render(
                root,
                "cart",
                vec![
                    (
                        "page_title".into(),
                        Value::Str("Karfan — Golfsetrið Akureyri".into()),
                    ),
                    ("cart".into(), cart::cart_value(&summary)),
                    (
                        "subtotal_label".into(),
                        Value::Str(shop::format_isk(summary.subtotal)),
                    ),
                    ("has_items".into(), Value::Bool(!summary.items.is_empty())),
                ],
                auth,
                req,
            );
            if created && user.is_none() {
                resp = resp.with_header("Set-Cookie", &cart::cookie_header(&summary.id));
            }
            resp
        }
        Err(e) => json(500, &error_value(&e)),
    }
}

