/// Build the template engine from `root`. Called by `auth` to render login.
pub fn build_engine_pub(root: &Path) -> Result<akurai_template::Engine, String> {
    build_engine(root)
}

/// Load `backend/page.json` context. Called by `auth` to merge site globals.
pub fn load_context_pub(root: &Path) -> Value {
    load_context(root)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn slug_extraction_and_validation() {
        assert_eq!(slug_of("/frettir/abc-1", "/frettir/"), "abc-1");
        assert_eq!(slug_of("/frettir/abc/", "/frettir/"), "abc");
        assert!(valid_slug("6-7-payday-bokhald-og-vsk"));
        assert!(!valid_slug(""));
        assert!(!valid_slug("../etc/passwd"));
        assert!(!valid_slug("a/b"));
    }

    #[test]
    fn static_asset_detection() {
        assert!(is_static_asset("/styles.css"));
        assert!(is_static_asset("/img/logo.svg"));
        assert!(!is_static_asset("/frettir"));
        assert!(!is_static_asset("/index.html"));
    }

    #[test]
    fn resolve_rejects_traversal() {
        assert!(resolve(Path::new("/srv"), "/../../etc/passwd").is_none());
        assert!(resolve(Path::new("/srv"), "/ok/app.js").is_some());
        assert!(resolve(Path::new("/srv"), "/")
            .unwrap()
            .ends_with("index.html"));
    }

    #[test]
    fn route_data_rejects_traversal() {
        assert!(load_route_data(Path::new("/srv/frontend"), "../secrets.json").is_none());
        assert!(load_route_data(Path::new("/srv/frontend"), "").is_none());
        assert!(load_route_data(Path::new("/srv/frontend"), "data/missing.json").is_none());
    }

    #[test]
    fn health_reports_ok() {
        let v = health();
        assert_eq!(v.get("status").and_then(Value::as_str), Some("ok"));
        assert_eq!(v.get("app").and_then(Value::as_str), Some("golfsetridak"));
    }
}
